-- Turkish Blip & Map System - Client Side\nlocal QBCore = exports['qb-core']:GetCoreObject()\n\nlocal Locations = {\n    {name = 'Taksim Duragi', x = 425.5, y = -980.2, z = 28.4, sprite = 227, color = 5},\n    {name = 'Taksim Polis', x = 430.0, y = -950.0, z = 25.0, sprite = 227, color = 3},\n    {name = 'Ziraat Bankasi', x = 430.0, y = -975.0, z = 29.0, sprite = 108, color = 2},\n    {name = 'Eminonu Iskele', x = -520.5, y = -1020.3, z = 22.0, sprite = 358, color = 5},\n    {name = 'Eminonu Polis', x = -510.0, y = -1010.0, z = 22.0, sprite = 227, color = 3},\n    {name = 'Kadikoy Rihtim', x = 1150.0, y = -800.0, z = 57.6, sprite = 227, color = 4},\n    {name = 'Kadikoy Polis', x = 1100.0, y = -800.0, z = 57.0, sprite = 227, color = 3},\n    {name = 'Besiktas Merkezi', x = 250.0, y = -850.0, z = 50.0, sprite = 227, color = 2},\n}\n\nCreateThread(function()\n    Wait(1000)\n    for i, location in ipairs(Locations) do\n        local blip = AddBlipForCoord(location.x, location.y, location.z)\n        SetBlipSprite(blip, location.sprite)\n        SetBlipColour(blip, location.color)\n        SetBlipScale(blip, 0.8)\n        AddTextComponentString(location.name)\n        AddBlipNameFromTextComponent(blip)\n        Wait(50)\n    end\n    print('^2[Blip System] ' .. #Locations .. ' blip olusturuldu!^7')\nend)\n\nprint('^2[Turkish Blip System] Yuklendi!^7')"